#include <stdio.h>
#include <time.h>

void log_error(FILE* logfile, const char* function, const char* file, int line, const char* error_msg) {
    time_t now;
    struct tm* local;

    time(&now);
    local = localtime(&now);

    fprintf(logfile, "\n%s - %s(%d) : [%02d:%02d:%02d] - Error: %s\n", asctime(local), function, line, local->tm_hour, local->tm_min, local->tm_sec, error_msg);
}